import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { useParams, useNavigate } from "react-router-dom";

function ProductDetail()
{
    const navigate = useNavigate();
    const { category_slug, product_slug } = useParams();
    const [loading, setLoading] = useState(true);
    const [product, setProduct] = useState({});
    const [category, setCategory] = useState({});

    useEffect(() =>
    {
        let isMounted = true;

        axios.get(`/api/view-product-detail/${category_slug}/${product_slug}`).then(res =>
        {
            if (isMounted)
            {
                if (res.data.status === 200)
                {
                    setProduct(res.data.product);
                    setCategory(res.data.category);
                } else if (res.data.status === 404)
                {
                    navigate('/collections');
                    Swal.fire("Warning", res.data.message, "error");
                }
                setLoading(false);
            }
        }).catch(err =>
        {
            if (isMounted)
            {
                console.error("Error fetching product details:", err);
                Swal.fire("Error", "Could not fetch data. Please try again later.", "error");
                setLoading(false);
            }
        });

        return () =>
        {
            isMounted = false;
        };
    }, [category_slug, product_slug, navigate]);

    if (loading)
    {
        return <h4>Loading Product Details...</h4>;
    } else
    {
        var avail_stock = '';
        if (product.qty > 0)
        {
            avail_stock = (
                <div>
                    <label className="btn-sm btn-success px-4 mt-2">In stock</label>
                    <div className="row">
                        <div className="col-md-3 mt-3">
                            <div className="input-group">
                                <button type="button" className="input-group-text">-</button>
                                <div className="form-control text-center">1</div>
                                <button type="button" className="input-group-text">+</button>
                            </div>
                        </div>
                        <div className="col-md-3 mt-3">
                            <button type="button" className="btn btn-primary w-100">Add to Cart</button>
                        </div>
                    </div>
                </div>
            );
        } else
        {
            avail_stock = (
                <div>
                    <label className="btn-sm btn-danger px-4 mt-2">Out of stock</label>
                </div>
            );
        }

        return (
            <div>
                <div className="py-3 bg-warning">
                    <div className="container">
                        <h6>Collections / Category / Product</h6>
                    </div>
                </div>

                <div className="py-3">
                    <div className="container">
                        <div className="row">

                            <div className="col-md-4 border-end">
                                <img src="" alt="Product Image" className="w-100" />
                            </div>

                            <div className="col-md-8">
                                <h4>
                                    Product name
                                    <span className="float-end badge btn-sm btn-danger badge-pill"> Brand</span>
                                </h4>
                                <p>Product description</p>
                                <h4 className="mb-1">
                                    KSH: 9999
                                    <s className="ms-2"> KSH: 19999 </s>
                                </h4>
                                <div>
                                    <label className="btn-sm btn-success px-4 mt-2">In stock</label>

                                    <div className="row">
                                        <div className="col-md-3 mt-3">
                                            <div className="input-group">
                                                <button type="button" className="input-group-text">-</button>
                                                <input type="text" className="form-control text-center" value="1" />
                                                <button type="button" className="input-group-text">+</button>
                                            </div>
                                        </div>
                                        <div className="col-md-3 mt-3">
                                            <button type="button" className="btn btn-primary w-100">Add to Cart</button>
                                        </div>
                                    </div>

                                </div>

                                <button type="button" className="btn btn-danger mt-3">Add to Wishlist</button>

                            </div>

                        </div>
                    </div>
                </div>
            </div>
        );
    }
}

export default ProductDetail;
